```python
def find_zero(xs: list):
    from scipy.optimize import bisect

    def f(x):
        return poly(xs, x)

    return bisect(f, -1000, 1000)
```

```python
def find_zero(xs: list):
    a, b = 0, 1
    while poly(xs, b) > 0:
        a, b = b, b * 2
    while b - a > 1e-7:
        mid = (a + b) / 2
        if poly(xs, mid) * poly(xs, a) < 0:
            b = mid
        else:
            a = mid
    return (a + b) / 2
```

```python
def find_zero(xs: list):
    from scipy.optimize import fsolve

    def func(x):
        return poly(xs, x)

    return fsolve(func, 0)[0]
```

