```python
def triples_sum_to_zero(l: list):
    s = set(l)
    for i in range(len(l)):
        for j in range(i + 1, len(l)):
            k = -(l[i] + l[j])
            if k in s and k != l[i] and k != l[j]:
                return True
    return False
```

```python
def triples_sum_to_zero(l: list):
    l = list(set(l))
    n = len(l)
    for i in range(n):
        seen = set()
        target = -l[i]
        for j in range(i + 1, n):
            if target - l[j] in seen:
                return True
            seen.add(l[j])
    return False
```

